var val = Services.getValue(DetailAssessCosts.dataBinding);
var err = validateCurrencyValue(val, 999999.99);
if( null == err)
{	Services.setValue( DetailAssessCosts.dataBinding, WPU.formatToTwoDP(val));
}
return err;

